import unittest
from typing import List

class Solution:
    def findMinHeightTrees(self, n: int, edges: List[List[int]]) -> List[int]:
        if n == 1 or not edges:
            return [0]

        ans = []
        graph = {}

        # Initialize graph
        for i in range(n):
            graph[i] = set()

        for u, v in edges:
            graph[u].add(v)
            graph[v].add(u)

        # Find initial leaves
        for label in range(n):
            if len(graph[label]) == 1:
                ans.append(label)

        while n > 2:
            n -= len(ans)
            nextLeaves = []
            for leaf in ans:
                u = next(iter(graph[leaf]))
                graph[u].remove(leaf)
                if len(graph[u]) == 1:
                    nextLeaves.append(u)
            ans = nextLeaves

        return ans

class TestFindMinHeightTrees(unittest.TestCase):

    def test_findMinHeightTrees_single_node(self):
